const contact = $input.first().json;
const params = contact.custom_params || [];

function getParam(name) {
  const found = params.find(p => p.name === name);
  return found ? found.value : '';
}

function getCountryFromPhone(phone) {
  if (!phone) return '';
  const prefixMap = [
    { prefix: '65', country: 'Singapore' },
    { prefix: '60', country: 'Malaysia' },
    { prefix: '61', country: 'Australia' },
    { prefix: '852', country: 'Hong Kong' },
    { prefix: '971', country: 'Dubai' },
    { prefix: '64', country: 'New Zealand' },
  ];
  // Sort by prefix length descending so longer prefixes match first (e.g. 852 before 8)
  prefixMap.sort((a, b) => b.prefix.length - a.prefix.length);
  const match = prefixMap.find(entry => phone.startsWith(entry.prefix));
  if (match) return match.country;

  // US and Canada both use prefix 1 — distinguish by Canadian area codes
  if (phone.startsWith('1') && phone.length >= 4) {
    const areaCode = phone.substring(1, 4);
    const canadianAreaCodes = [
      '204','226','236','249','250','263','289','306','343','354','365','367',
      '368','382','403','416','418','428','431','437','438','450','460','468',
      '474','506','514','519','548','579','581','584','587','604','613','639',
      '647','672','683','705','709','742','753','778','780','782','807','819',
      '825','867','873','879','902','905'
    ];
    return canadianAreaCodes.includes(areaCode) ? 'Canada' : 'United States';
  }

  return 'Unknown';
}

const phone = contact.phone || getParam('phone') || '';
const country = getParam('country') || getCountryFromPhone(phone);

return [{
  json: {
    name:       contact.name || getParam('name')            || '',
    phone:      phone,
    country:    country,
    restaurant: getParam('restaurant')                      || '',
    email:      getParam('email')                           || '',
    role:       getParam('restaurant_role')                 || '',
    attio_record_id:       getParam('attio_record_id')      || ''
  }
}];

const extracted = $('Validate Extracted Data').item.json;
const existing  = $('Parse Contact Details').item.json;

const toProperCase = (str) => str.replace(/\w\S*/g, (w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase());

let hasNewData = false;

if (extracted.restaurant_name && !existing.restaurant) hasNewData = true;
if (extracted.email           && !existing.email)       hasNewData = true;
if (extracted.role            && !existing.role)        hasNewData = true;

const restaurant_name = toProperCase(existing.restaurant || extracted.restaurant_name || '');
const email           = (existing.email || extracted.email || '').toLowerCase();
const role            = toProperCase(existing.role || extracted.role || '');
const waId            = $('Receive Reply').item.json.body.waId;

// Build WATI body — only include params with values
const watiCustomParams = [];
if (restaurant_name) watiCustomParams.push({ name: 'restaurant',      value: restaurant_name });
if (email)           watiCustomParams.push({ name: 'email',           value: email });
if (role)            watiCustomParams.push({ name: 'restaurant_role', value: role });

// Build Attio body — only include fields with values
const attioValues = {};
if (restaurant_name) attioValues.person_restaurant_name = restaurant_name;
if (email)           attioValues.email_addresses        = [email];
if (role)            attioValues.job_title              = role;

return [{
  json: {
    hasNewData,
    waId,
    attio_record_id: existing.attio_record_id,
    watiBody:        { contacts: [{ target: waId, customParams: watiCustomParams }] },
    attioBody:       { data: { values: attioValues } }
  }
}];

// Merge LLM extraction with regex email check + gap-fill validation.
const llmExtracted = $('Extract Lead Data').item.json.output || {};
const existing = $('Parse Contact Details').item.json;
const chatHistory = $('Map fields').item.json.chat_history || '';
const latestMessages = $('Map fields').item.json.latest_messages || '';

// Email: prefer regex (more reliable), fall back to LLM extraction
let extractedEmail = null;
if (!existing.email) {
  const allText = chatHistory + '\n' + latestMessages;
  const prospectLines = allText.split('\n')
    .filter(line => line.includes('Prospect:'))
    .map(line => line.replace(/^\[.*?\]\s*Prospect:\s*/, ''));
  const emailMatch = prospectLines.join(' ').match(/[\w.-]+@[\w.-]+\.\w{2,}/);
  extractedEmail = emailMatch
    ? emailMatch[0].toLowerCase()
    : (llmExtracted.email && llmExtracted.email !== '' ? llmExtracted.email.toLowerCase() : null);
}

// Restaurant name and role: from LLM extraction
const extractedRestaurant = (llmExtracted.restaurant_name && llmExtracted.restaurant_name !== '') ? llmExtracted.restaurant_name : null;
const extractedRole = (llmExtracted.role && llmExtracted.role !== '') ? llmExtracted.role : null;

return [{
  json: {
    restaurant_name: extractedRestaurant,
    email: extractedEmail || existing.email || null,
    role: extractedRole,
    has_new_data: !!(
      (extractedRestaurant && !existing.restaurant) ||
      (extractedEmail && !existing.email) ||
      (extractedRole && !existing.role)
    )
  }
}];
